export type Item = {
  type: string;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;
export type ScenarioResult = { results: StepResult[] };

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const quotePremium = (items: Item[]): number => {
  const itemsBase = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  const firstInsurance = itemsBase * 0.1;
  return Math.ceil(itemsBase + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

