import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge: empty
  it("empty item list yields premium of 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums per main item (with 5 G fee)
  it("quote with a single plain sword: 100 base + 10 first insurance + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote with a single plain amulet: 60 base + 6 first insurance + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote with a single plain staff: 80 base + 8 first insurance + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote with a single plain potion: 40 base + 4 first insurance + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Components and building block
  it("2 runes: base 50 G (2 x 25) plus first-insurance and fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes form a block: base 60 G plus first-insurance and fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes: base 100 G (no block — block requires exactly 3) plus modifiers = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes: base 175 G (no block — > 3 components do not split into a block) plus modifiers = 198 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // Alike components clarification (Q: same type, not same family)
  it("2 runes + 1 moonstone: base 75 G (no block — different types) plus modifiers = 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones: base 120 G (two separate blocks) plus modifiers = 137 G", () => {
    const items = [
      ...Array.from({ length: 3 }, () => ({ type: "rune" })),
      ...Array.from({ length: 3 }, () => ({ type: "moonstone" })),
    ];
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Item-specific modifiers
  it("cursed sword alone (newcomer): 100 base + 50 curse + 10 first insurance + 5 fee = 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", cursed: true }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("high-enchantment sword (enchantment 5) alone (newcomer): 100 + 30 + 10 first insurance + 5 fee = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", enchantment: 5 }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 has both curse and high-enchantment surcharges");

  // Multi-item modifier scope
  it.todo("cursed sword + plain amulet: item-specific curse applies only to sword (210 G before further modifiers and fee)");

  // Loyalty discount threshold
  it.todo("customer with exactly 2 years with MHPCO gets the 20% loyalty discount");

  // Rounding in MHPCO's favor
  it.todo("a premium calculation that yields 197.5 G rounds up to 198 G");

  // Integration: newcomer with a cursed sword
  it.todo("newcomer (0 yrs, no prior contract) with a cursed steel sword (ench 3): premium 165 G");

  // Integration: long-standing customer's second contract
  it.todo("long-standing customer (3 yrs) on second contract with cursed sword (ench 7): premium 160 G; first-insurance surcharge still applies");

  // Claim — standard reimbursement
  it.todo("regular sword (steel, ench 3) damage 500 G: payout 400 G (full minus 100 deductible)");
  it.todo("rune (insurance 250 G) damage 200 G: payout 100 G (full minus 100 deductible; no enchantment/material clause)");

  // Claim — enchantment threshold vs dragon material
  it.todo("dragon-material sword, enchantment 9, damage 1000 G: payout 400 G (50% rule, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G: payout 700 G (full reimbursement, then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G: payout 400 G (50% rule, then deductible)");
  it.todo("dragon-material sword, enchantment 8 exactly, damage 1000 G: payout 400 G (high-ench clause wins, then deductible)");

  // Claim — deductible per damage event
  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G (deductible per item)");

  // Claim — multiple items of same type
  it.todo("policy covers two swords: insurance sum 2000 G, cap 4000 G; two sword damages -> separate deductibles");
  it.todo("damages array has more entries of a type than policy covers: CLI exits non-zero (claim rejected)");

  // Cap exhaustion
  it.todo("policy: sword + amulet -> insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword: cap 2000 G (based on unmodified insurance value; premium modifiers do not raise cap)");
  it.todo("sword + 3 runes (block): insurance sum 1750 G (block discount affects premium only, not cap)");
  it.todo("successive claims on a sword (cap 2000): first 1500 -> 1400 payout, cap remaining 600; second 1500 -> 600 payout, cap remaining 0");

  // Rounding — payout in MHPCO's favor
  it.todo("a payout calculation that yields 350.5 G rounds down to 350 G");

  // Error/edge cases (CLI exits non-zero)
  it.todo("quote includes an item with an unknown type: CLI exits non-zero, error on stderr, no results on stdout");
  it.todo("claim references an item not covered by the policy: CLI exits non-zero, error on stderr");
  it.todo("claim contains a damage entry with negative amount: CLI exits non-zero, error on stderr");

  // CLI smoke (stdin/stdout JSON shape)
  it.todo("CLI: reads scenario from stdin and writes {results: [...]} JSON to stdout in step order");
});

