const countsByType = <T extends { type?: string; itemType?: string }>(
  entries: T[],
  keyFn: (e: T) => string,
): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const entry of entries) {
    const k = keyFn(entry);
    counts.set(k, (counts.get(k) ?? 0) + 1);
  }
  return counts;
};

const validateClaimCoverage = (damages: Damage[], items: Item[]): void => {
  const itemCounts = countsByType(items, (i) => i.type);
  const damageCounts = countsByType(damages, (d) => d.itemType);
  for (const [type, count] of damageCounts) {
    if (count > (itemCounts.get(type) ?? 0)) {
      throw new Error(
        `claim has ${count} damage(s) of type "${type}" but policy only covers ${itemCounts.get(type) ?? 0}`,
      );
    }
  }
};

const claimStep = (step: ClaimStep, policy: Policy): ClaimResult => {
  validateClaimCoverage(step.incident.damages, policy.items);
  const payout = sumDamagePayouts(step.incident.damages, policy.items);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

